// src/Login.js
import React, { useState } from "react";
import { createClient } from "@supabase/supabase-js";
import { motion } from "framer-motion";
import { Truck, Eye, EyeOff, Loader2, LogIn } from "lucide-react";

const supabase = createClient(
    process.env.REACT_APP_SUPABASE_URL,
    process.env.REACT_APP_SUPABASE_KEY
);

export default function Login({ onLoginSuccess }) {
    const [email, setEmail] = useState("");      // kullanici_adi
    const [password, setPassword] = useState(""); // sifre
    const [loading, setLoading] = useState(false);
    const [show, setShow] = useState(false);
    const [err, setErr] = useState("");

    const handleLogin = async (e) => {
        e.preventDefault();
        setErr("");
        setLoading(true);
        try {
            const { data, error } = await supabase
                .from("Login")
                .select("*")
                .eq("kullanici_adi", email)
                .eq("sifre", password)
                .single();

            if (error || !data) {
                setErr("❌ Hatalı kullanıcı adı veya şifre!");
                return;
            }

            localStorage.setItem("kullanici", JSON.stringify(data));

            const reelUser =
                data.Reel_kullanici ??
                data.reel_kullanici ??
                data.reelUserName ??
                data.reel_username ??
                "";
            const reelPass =
                data.Reel_sifre ??
                data.reel_sifre ??
                data.reelPassword ??
                data.reel_password ??
                "";

            if (reelUser) localStorage.setItem("Reel_kullanici", reelUser);
            if (reelPass) localStorage.setItem("Reel_sifre", reelPass);
            if (reelUser && reelPass) {
                localStorage.setItem("reelCreds", JSON.stringify({ userName: reelUser, password: reelPass }));
            }

            onLoginSuccess?.();
        } catch (e) {
            console.error(e);
            setErr("Beklenmeyen bir hata oluştu. Lütfen tekrar deneyin.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="logi-wrap">
            <style>{css}</style>

            {/* Arka plan/tema */}
            <div className="bg">
                <div className="lane lane-left" />
                <div className="lane lane-right" />
                <div className="grid" />
            </div>

            {/* İçerik */}
            <motion.div
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.45 }}
                className="panel"
            >
                <div className="brand">
                    <span className="badge">
                        <Truck size={16} />
                        LogiPro · Lojistik Operasyon
                    </span>
                    <h1>
                        Akıllı Lojistik için <span>güvenli</span> giriş
                    </h1>
                    <p>Sevkiyat, depo ve filo verilerinize tek yerden erişin.</p>
                </div>

                <form className="card" onSubmit={handleLogin}>
                    <div className="card-head">
                        <LogIn size={18} />
                        <span>Giriş Yap</span>
                    </div>

                    <label className="label" htmlFor="username">Kullanıcı Adı</label>
                    <input
                        id="username"
                        className="input"
                        type="text"
                        placeholder="kullanici_adi"
                        value={email}
                        onChange={(e) => setEmail(e.target.value)}
                        autoComplete="username"
                        required
                    />

                    <label className="label" htmlFor="password">Şifre</label>
                    <div className="pass">
                        <input
                            id="password"
                            className="input"
                            type={show ? "text" : "password"}
                            placeholder="••••••••"
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            autoComplete="current-password"
                            required
                        />
                        <button
                            type="button"
                            className="eye"
                            aria-label={show ? "Şifreyi gizle" : "Şifreyi göster"}
                            onClick={() => setShow((s) => !s)}
                        >
                            {show ? <EyeOff size={16} /> : <Eye size={16} />}
                        </button>
                    </div>

                    {err && <div className="alert">{err}</div>}

                    <button className="btn" type="submit" disabled={loading}>
                        {loading ? (
                            <span className="btn-inner">
                                <Loader2 className="spin" size={16} /> Giriş yapılıyor…
                            </span>
                        ) : (
                            "Giriş"
                        )}
                    </button>

                    <p className="muted">
                        Devam ederek <a href="#">Kullanım Koşulları</a>’nı kabul edersiniz.
                    </p>
                </form>
            </motion.div>
        </div>
    );
}

/* Minimal ve modern CSS (tek dosya) */
const css = `
:root{
  --bg-0:#070c16;
  --bg-1:#0b1424;
  --card:#0f1b31aa;
  --glass:rgba(255,255,255,0.06);
  --border:rgba(255,255,255,0.12);
  --text:#e6edf3;
  --muted:#93a4ba;
  --primary:#38bdf8;  /* sky-400 */
  --primary-2:#0ea5e9;/* sky-500 */
  --red:#ef4444;
  --shadow: 0 20px 60px rgba(2,8,23,.55);
}

*{box-sizing:border-box}
html,body,#root,.logi-wrap{height:100%}
body{margin:0;background:var(--bg-0);color:var(--text);font:14px/1.4 ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Ubuntu, Cantarell, Noto Sans, Arial, Apple Color Emoji, Segoe UI Emoji}

.logi-wrap{display:grid;place-items:center;position:relative;overflow:hidden}

/* Background */
.bg{position:absolute;inset:0}
.grid{
  position:absolute;inset:0;opacity:.18;mix-blend-overlay;
  background:
    radial-gradient(1200px 600px at 95% 0%, rgba(56,189,248,.18), transparent 60%),
    radial-gradient(900px 500px at 0% 100%, rgba(14,165,233,.14), transparent 55%),
    linear-gradient(180deg, var(--bg-0), var(--bg-1));
}
.lane{
  position:absolute; top:50%; width:300px; height:140%;
  filter: blur(20px); pointer-events:none; opacity:.6;
  background: linear-gradient(to bottom, rgba(255,255,255,.08), rgba(255,255,255,.04), transparent);
}
.lane-left{ left:-70px; transform:translateY(-50%) rotate(18deg) }
.lane-right{ right:-70px; transform:translateY(-50%) rotate(-18deg);
  background: linear-gradient(to bottom, rgba(56,189,248,.12), rgba(14,165,233,.08), transparent);
}

/* Content */
.panel{
  position:relative; z-index:1;
  width:min(980px, 92vw);
  display:grid; gap:24px;
  grid-template-columns: 1.1fr 1fr;
}
@media (max-width: 920px){ .panel{ grid-template-columns: 1fr; } }

/* Brand/Hero */
.brand{padding:12px 6px}
.badge{
  display:inline-flex; gap:8px; align-items:center;
  padding:8px 12px; border-radius:999px; border:1px solid var(--border);
  background:var(--glass); color:#d3e1f1; font-size:12px; backdrop-filter: blur(8px);
}
.brand h1{
  margin:10px 0 6px; font-size:clamp(26px, 4vw, 38px); line-height:1.12; font-weight:800;
}
.brand h1 span{ color:var(--primary) }
.brand p{ color:var(--muted); margin:6px 0 0 }

/* Card / Form */
