  border-radius:18px;
  box-shadow: var(--shadow);
  padding:18px;
  display:grid; gap:12px;
}
@media (max-width: 920px){ .card{ margin:0 auto; } }

.card-head{
  display:flex; align-items:center; gap:8px;
  padding:6px 2px 10px; border-bottom:1px solid var(--border);
  font-weight:700; color:#e8f0ff;
}

.label{ color:#c8d6ea; font-size:12px; }
.input{
  width:100%; border:1px solid var(--border); border-radius:12px;
  background:var(--glass); color:var(--text);
  padding:12px 14px; outline:none; transition:border-color .2s, box-shadow .2s;
}
.input::placeholder{ color:#9cb1cb }
.input:focus{ border-color: rgba(56,189,248,.5); box-shadow:0 0 0 4px rgba(56,189,248,.15) }

.pass{ position:relative }
.eye{
  position:absolute; right:10px; top:50%; transform:translateY(-50%);
  border:0; background:transparent; color:#c9d7e8; cursor:pointer; padding:4px;
}
.eye:hover{ color:#fff }

.alert{
  background: rgba(239,68,68,.12);
  border:1px solid rgba(239,68,68,.35);
  color:#fecaca; border-radius:10px; padding:10px 12px; font-size:13px;
}

/* Button */
.btn{
  width:100%; border:0; border-radius:12px;
  background: linear-gradient(90deg, var(--primary-2), var(--primary));
  color:white; font-weight:700; padding:12px 14px; cursor:pointer;
  transition: filter .2s, transform .03s;
}
.btn:hover{ filter: brightness(1.06) }
.btn:active{ transform: translateY(1px) }
.btn:disabled{ opacity:.65; cursor:not-allowed }
.btn-inner{ display:inline-flex; gap:8px; align-items:center }
.spin{ animation:spin 1s linear infinite }
@keyframes spin{ to{ transform:rotate(360deg) } }

/* Footer text */
.muted{ text-align:center; color:var(--muted); font-size:12px; margin:6px 0 0 }
.muted a{ color:#d8e6fb; }
.muted a:hover{ color:#fff }
`;
